// // This module implements a combinational logic circuit that outputs high when either A1 and A2 are high and B1 is low, or when both A1 and A2 are low and B1 is high.
module top_module(
    input A1,
    input A2,
    input B1_N,
    output Y
);assign Y = (A1 & A2 & ~B1_N) | (~A1 & ~A2 & ~B1_N);

endmodule
